var emreboBridgeModule = angular.module("emreboBridgeModule",['oc.lazyLoad']);
var EBOEMRBridgeController = ['$scope','$ocLazyLoad','$http','$timeout','$modal',
    function ($scope,$ocLazyLoad, $http,$timeout, $modal) {
        $scope.EBOClaimPage = '';
        $scope.initEBOEMRBridge=function(){
            // console.log("Inilization Done");
        };

        $scope.launchPopup=function(type,id,parentScreenName,parentScope){
            if(parentScreenName && parentScreenName.toUpperCase()==='EBOREPORT'){
                let uType = type.toUpperCase();
                switch (uType) {
                    case "CLAIM":
                        openClaimScreen(id,parentScreenName,parentScope);
                        break;
                    case "ENCOUNTER":
                        // code block
                        break;
                    case "PATIENT-ACCOUNT":
                        openPatientAccount(id,parentScreenName,parentScope);
                        break;
                    default:
                        ecwAlert("Integration is pending","eClinicalWorks",'','','bluetheme');
                }
            }
        };

        let openPatientAccount=function(id,parentScreenName,parentScope){
            let params = {patientId:id,contextFrom:'EBOReport',parentScreen:parentScreenName};
            loadAccountsInquiry($ocLazyLoad,$modal,params);
        }

        let openClaimScreen=function(id,parentScreenName,parentScope){
            var params = $.param({InvId:id});
            let request = $http.post(makeURL("/mobiledoc/emr/eboemrbridge/getClaimData"),params);
            request.then(function(resp){
                if(resp.data){
                    let oData = resp.data;
                    let param = {claimId:id,parentScreen:parentScreenName,encounterId:oData.encounterId,patientId:oData.patientId};
                    if(oData.type === 0){
                        loadHCFAClaim($ocLazyLoad, $modal, param, parentScope , false);
                    }else if(oData.type === 1){
                        $scope.EBOClaimPage='';
                        loadUBClaim($ocLazyLoad,param,$scope, 'EBOClaimPage' );
                    }else if(oData.type === 2){
                        $scope.EBOClaimPage='';
                        loadDentalClaim($ocLazyLoad,param,$scope, 'EBOClaimPage' );
                    }
                }
            });
        }

    }];
emreboBridgeModule.controller('EBOEMRBridgeController', EBOEMRBridgeController);

function launchPopupFromEBOReport(payload,parentScreenName){
    let bridgeScope = getEBOEMRBridgeScope();
    let eboScope = getAngularScopeFromControllerName('EboPortalController');
    if(eboScope===null || eboScope=== undefined){
        eboScope = {};
    }
    let obj = JSON.parse(payload);
    if(obj && obj.type !== undefined && obj.id !== undefined){
        let type = obj.type;
        let id = obj.id;
        bridgeScope.launchPopup(type,id,parentScreenName,eboScope);
    }else{
        alert('Ínvlid Input');
    }
}

function getEBOEMRBridgeScope(){
    return angular.element("[ng-controller=EBOEMRBridgeController]").scope();
}
function getAngularScopeFromControllerName(controllerName){
    var scope= {};
    if(controllerName){
        var element;
        if(controllerName.toLowerCase().contains(" as ")){
            element=angular.element("[ng-controller='"+controllerName+"']")
        }else{
            element=angular.element("[ng-controller="+controllerName+"]")
        }
        if(element.length>0){
            scope=element.scope();
        }
    }
    return scope;
}

